class Solution {
public:
    int numberOfSpecialChars(string word) {
        int count = 0;
        for (char c = 'a'; c <= 'z'; c++) {
            bool foundLower = false, foundUpper = false;
            for (char ch : word) {
                if (ch == c) {
                    foundLower = true;
                } else if (ch == c - 32 && !foundLower) {
                    break;
                } else if (ch == c - 32 && foundLower) {
                    foundUpper = true;
                }
            }
            if (foundLower && foundUpper) {
                count++;
            }
        }
        return count;
    }
};

